<?php
declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/portal_estudiante_layout.php';require_once dirname(__DIR__,2).'/includes/academico_flujo.php';
exigirPerfilCompleto();$id=filter_var($_GET['id']??0,FILTER_VALIDATE_INT,['options'=>['min_range'=>1]])?:0;$pdo=obtenerConexion();
$q=$pdo->prepare("SELECT i.*,a.nombre,a.codigo,a.descripcion,s.codigo seccion,CONCAT_WS(' ',d.nombre,d.apellido) docente FROM inscripciones_capacitacion i JOIN asignaturas a ON a.id=i.asignatura_id JOIN capacitacion_secciones s ON s.id=i.seccion_id JOIN usuarios d ON d.id=i.docente_id WHERE i.usuario_id=:u AND i.asignatura_id=:a AND i.estado IN('inscrito','finalizado') LIMIT 1");$q->execute(['u'=>$_SESSION['usuario_id'],'a'=>$id]);$curso=$q->fetch();if(!$curso)mostrarPaginaErrorAtenea(403);
$portal=portalEstudianteCabecera($curso['nombre'],'cursos','Contenido de tu sección '.$curso['seccion'].'.');
$q=$pdo->prepare("SELECT c.*,(SELECT estado FROM entregas_contenido e WHERE e.contenido_id=c.id AND e.estudiante_id=:u ORDER BY intento DESC LIMIT 1) entrega_estado,p.visto_at,p.completado_at FROM contenidos c LEFT JOIN progreso_contenido p ON p.contenido_id=c.id AND p.inscripcion_id=:i WHERE c.seccion_id=:s AND c.estado='activo' AND c.activo=1 AND (c.fecha_publicacion IS NULL OR c.fecha_publicacion<=NOW()) ORDER BY c.modulo,c.orden,c.id");$q->execute(['u'=>$_SESSION['usuario_id'],'i'=>$curso['id'],'s'=>$curso['seccion_id']]);$contenidos=$q->fetchAll();$progreso=progresoInscripcion($pdo,(int)$curso['id']);$modulo='';
?>
<div class="row g-4"><div class="col-lg-8"><div class="card"><div class="card-body"><span class="badge bg-primary"><?=atenea_e($curso['codigo'])?></span><h1 class="h3 mt-3"><?=atenea_e($curso['nombre'])?></h1><p><?=atenea_e($curso['descripcion'])?></p><p><strong>Sección:</strong> <?=atenea_e($curso['seccion'])?> · <strong>Docente:</strong> <?=atenea_e($curso['docente'])?></p><?php foreach($contenidos as$c):if($modulo!==$c['modulo']):$modulo=$c['modulo'];?><h2 class="h5 mt-4 border-bottom pb-2"><?=atenea_e($modulo)?></h2><?php endif;$estado=!empty($c['completado_at'])||$c['entrega_estado']==='aprobada'?['Completado','success']:($c['entrega_estado']?[$c['entrega_estado'],'info']:(!empty($c['visto_at'])?['Visto','secondary']:['Pendiente','light']));?><a class="aula-list-item mb-2" href="<?=atenea_url('src/estudiantes/contenido.php?id='.(int)$c['id'])?>"><div class="d-flex justify-content-between"><strong><?=atenea_e($c['titulo'])?></strong><span class="badge bg-<?=$estado[1]?>"><?=atenea_e(ucfirst(str_replace('_',' ',$estado[0])))?></span></div><small class="text-muted"><?=atenea_e(ucfirst($c['tipo']))?> · <?=$c['obligatorio']?'Obligatorio':'Opcional'?><?php if($c['fecha_limite']):?> · Límite <?=date('d/m/Y H:i',strtotime($c['fecha_limite']))?><?php endif;?></small></a><?php endforeach;?><?php if(!$contenidos):?><div class="aula-empty"><i class="bi bi-journal-x"></i><p class="mt-2 mb-0">No hay contenidos publicados para tu sección.</p></div><?php endif;?></div></div></div><div class="col-lg-4"><div class="card"><div class="card-body"><h2 class="h5">Mi progreso</h2><div class="progress mb-2" style="height:18px"><div class="progress-bar" style="width:<?=min(100,(float)$progreso['porcentaje'])?>%"><?=$progreso['porcentaje']?>%</div></div><dl class="row small"><dt class="col-8">Contenidos vistos</dt><dd class="col-4"><?=$progreso['contenidos_vistos']?></dd><dt class="col-8">Pendientes</dt><dd class="col-4"><?=$progreso['entregas_pendientes']?></dd><dt class="col-8">Aprobadas</dt><dd class="col-4"><?=$progreso['entregas_aprobadas']?></dd><dt class="col-8">Correcciones</dt><dd class="col-4"><?=$progreso['entregas_rechazadas']?></dd><dt class="col-8">Promedio</dt><dd class="col-4"><?=$progreso['promedio']!==null?number_format($progreso['promedio'],2):'—'?></dd></dl><small>Última actividad: <?=atenea_e((string)$progreso['ultima_actividad'])?></small></div></div></div></div><?php portalEstudiantePie();
